Sample Magic Numbers The C code sequences in Figures 3-34 and 3-35 produce the
 magic numbers and shift values for signed and unsigned divisors,
 respectively. The derivation of these algorithms is beyond the
 scope of this book, but it is given in Warren [1992] and Granlund
 and Montgomery [1994].

Figure 3-34. Signed Division Magic Number Computation Code Sequence
 struct ms {int m; /* magic number */
 int s;}; /* shift amount */

 struct ms magic(int d)
 /* must have 2 <= d <= 231-1 or -231 <= d <= -2 */
 {
 int p;
 unsigned int ad, anc, delta, q1, r1, q2, r2, t;
 const unsigned int two31 = 2147483648;/* 231 */
 struct ms mag;

 ad = abs(d);
 t = two31 + ((unsigned int)d >> 31);
 anc = t - 1 - t%ad; /* absolute value of nc */
 p = 31; /* initialize p */
 q1 = two31/anc; /* initialize q1 = 2p/abs(nc) */
 r1 = two31 - q1*anc;/* initialize r1 = rem(2p,abs(nc)) */
 q2 = two31/ad; /* initialize q2 = 2p/abs(d) */
 r2 = two31 - q2*ad; /* initialize r2 = rem(2p,abs(d)) */
 do {
 p = p + 1;
 q1 = 2*q1; /* update q1 = 2p/abs(nc) */
 r1 = 2*r1; /* update r1 = rem(2p/abs(nc)) */
 if (r1 >= anc) { /* must be unsigned comparison */
 q1 = q1 + 1;
 r1 = r1 - anc;
 }
 q2 = 2*q2 /* update q2 = 2p/abs(d) */
 r2 = 2*r2 /* update r2 = rem(2p/abs(d)) */
 if (r2 >= ad) { /* must be unsigned comparison */
 q2 = q2 + 1;

Chapter 3. Code Selection: Integer and String Operations 57

Figure 3-34. Signed Division Magic Number Computation Code Sequence (continued)
 r2 = r2 - ad;
 }
 delta = ad - r2;
 } while (q1 < delta || (q1 == delta && r1 == 0));

 mag.m = q2 + 1;
 if (d < 0) mag.m = -mag.m; /* resulting magic number */
 mag.s = p - 32; /* resulting shift */
 return mag;
 }

Figure 3-35. Unsigned Division Magic Number Computation Code Sequence
 struct mu {unsigned int m;/* magic number */
 int a; /* ‚Äúadd‚ÄĚ indicator */
 int s;} /* shift amount */

 struct mu magicu(unsigned int d)
 /* must have 1 <= d <= 232-1 */
 {
 int p;
 unsigned int nc, delta, q1, r1, q2, r2;
 struct mu magu;

 magu.a = 0; /* initialize ‚Äúadd‚ÄĚ indicator */
 nc = - 1 - (-d)%d;
 p = 31; /* initialize p */
 q1 = 0x80000000/nc; /* initialize q1 = 2p/nc */
 r1 = 0x80000000 - q1*nc;/* initialize r1 = rem(2p,nc) */
 q2 = 0x7FFFFFFF/d; /* initialize q2 = (2p-1)/d */
 r2 = 0x7FFFFFFF - q2*d; /* initialize r2 = rem((2p-1),d) */
 do {
 p = p + 1;
 if (r1 >= nc - r1 ) {
 q1 = 2*q1 + 1; /* update q1 */
 r1 = 2*r1 - nc; /* update r1 */

