 int field;
 } SS,*P_SS;

 P_SS p_s;

 void t001(int i,P_SS x)
 { P_SS p;

 for(p = p_s; ; p = p->p_nxt){
 if(p->p_nxt == x) break;
 }
 p->field = i;
 }

